# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
import threading
import uuid
import os

try:
    from sklearn.linear_model import LogisticRegression
    from sklearn.feature_extraction import DictVectorizer
    import joblib
except Exception:
    LogisticRegression = None
    DictVectorizer = None
    joblib = None

app = Flask(__name__)

lock = threading.Lock()

images = {}
annotations = defaultdict(list)
aggregated_labels = {}
model = None
vectorizer = None

MODEL_PATH = os.environ.get("MODEL_PATH", "crowd_model.joblib")


def majority_vote(labels):
    if not labels:
        return None
    counts = Counter(labels)
    max_count = max(counts.values())
    winners = [label for label, count in counts.items() if count == max_count]
    return sorted(winners)[0]


def extract_features(image):
    if isinstance(image, dict):
        return image
    return {"image_id": str(image)}


@app.route("/images", methods=["POST"])
def add_image():
    data = request.get_json(force=True, silent=True) or {}
    image_id = data.get("image_id") or str(uuid.uuid4())
    image_data = data.get("image_data")
    with lock:
        images[image_id] = {
            "image_id": image_id,
            "image_data": image_data,
        }
    return jsonify({"image_id": image_id}), 201


@app.route("/images/<image_id>", methods=["GET"])
def get_image(image_id):
    with lock:
        if image_id not in images:
            return jsonify({"error": "image not found"}), 404
        return jsonify(images[image_id])


@app.route("/annotations", methods=["POST"])
def submit_annotation():
    data = request.get_json(force=True, silent=True) or {}
    image_id = data.get("image_id")
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if not image_id or not annotator_id or label is None:
        return jsonify({"error": "image_id, annotator_id, and label are required"}), 400

    with lock:
        if image_id not in images:
            return jsonify({"error": "image not found"}), 404

        annotations[image_id].append(
            {
                "annotator_id": annotator_id,
                "label": label,
            }
        )

        labels = [a["label"] for a in annotations[image_id]]
        aggregated = majority_vote(labels)
        aggregated_labels[image_id] = aggregated

    return jsonify(
        {
            "image_id": image_id,
            "annotator_id": annotator_id,
            "label": label,
            "aggregated_label": aggregated,
        }
    ), 201


@app.route("/annotations/<image_id>", methods=["GET"])
def get_annotations(image_id):
    with lock:
        if image_id not in images:
            return jsonify({"error": "image not found"}), 404
        return jsonify(
            {
                "image_id": image_id,
                "annotations": annotations.get(image_id, []),
                "aggregated_label": aggregated_labels.get(image_id),
            }
        )


@app.route("/aggregate/<image_id>", methods=["POST"])
def aggregate_image(image_id):
    with lock:
        if image_id not in images:
            return jsonify({"error": "image not found"}), 404
        labels = [a["label"] for a in annotations.get(image_id, [])]
        aggregated = majority_vote(labels)
        aggregated_labels[image_id] = aggregated
    return jsonify({"image_id": image_id, "aggregated_label": aggregated})


@app.route("/train", methods=["POST"])
def train_model():
    global model, vectorizer

    with lock:
        train_items = []
        train_labels = []
        for image_id, label in aggregated_labels.items():
            if label is None:
                continue
            train_items.append(extract_features(images[image_id]))
            train_labels.append(label)

    if not train_items:
        return jsonify({"error": "no labeled data available"}), 400

    if LogisticRegression is None or DictVectorizer is None:
        return jsonify({"error": "scikit-learn is not available"}), 500

    vectorizer = DictVectorizer(sparse=True)
    X = vectorizer.fit_transform(train_items)

    model = LogisticRegression(max_iter=1000)
    model.fit(X, train_labels)

    if joblib is not None:
        joblib.dump({"model": model, "vectorizer": vectorizer}, MODEL_PATH)

    return jsonify(
        {
            "status": "trained",
            "num_samples": len(train_items),
            "classes": list(model.classes_),
        }
    )


@app.route("/predict/<image_id>", methods=["GET"])
def predict(image_id):
    with lock:
        if image_id not in images:
            return jsonify({"error": "image not found"}), 404
        if model is None or vectorizer is None:
            return jsonify({"error": "model not trained"}), 400
        features = extract_features(images[image_id])

    X = vectorizer.transform([features])
    pred = model.predict(X)[0]
    probs = None
    if hasattr(model, "predict_proba"):
        probs = model.predict_proba(X)[0].tolist()

    return jsonify(
        {
            "image_id": image_id,
            "prediction": pred,
            "probabilities": probs,
        }
    )


@app.route("/load_model", methods=["POST"])
def load_model():
    global model, vectorizer
    if joblib is None:
        return jsonify({"error": "joblib is not available"}), 500
    if not os.path.exists(MODEL_PATH):
        return jsonify({"error": "model file not found"}), 404

    data = joblib.load(MODEL_PATH)
    model = data.get("model")
    vectorizer = data.get("vectorizer")
    return jsonify({"status": "loaded"})


@app.route("/status", methods=["GET"])
def status():
    with lock:
        return jsonify(
            {
                "num_images": len(images),
                "num_images_labeled": sum(1 for v in aggregated_labels.values() if v is not None),
                "trained": model is not None,
            }
        )


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)))